// Eclipse OS desktop shell - ASCII moon field renderer (G9 extraction).
//
// Moved verbatim out of baseline/desktopStaticBehavior.ts. The renderer stays
// intentionally imperative (untyped) because G10 promotes the moon foundations
// later; logic, timings, motion, custom events (moonposchange / moonspeedchange /
// themechange) and the window.__MOON_ALBEDO / window.__eclipseMoon globals are
// unchanged. __MOON_ALBEDO is assigned at module load, exactly as the source did.

// --- source lines 2078-2081 ---
window.__MOON_ALBEDO = { w: 384, h: 192, data: "" };

